<?php
 namespace WPAICG\Vector\Providers\OpenAI\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_OpenAI_Strategy; use WPAICG\Core\Providers\OpenAI\OpenAIUrlBuilder; use WP_Error; use CURLFile; if (!defined('ABSPATH')) { exit; } function upload_file_for_vector_store_logic(AIPKit_Vector_OpenAI_Strategy $strategyInstance, string $file_path, string $original_filename, string $purpose = 'assistants_file'): array|WP_Error { if (!$strategyInstance->get_is_connected_status()) { return new WP_Error('not_connected', __('Not connected to OpenAI.', 'gpt3-ai-content-generator')); } if (!file_exists($file_path) || !is_readable($file_path)) { return new WP_Error('file_not_readable', __('File not found or not readable at path: ', 'gpt3-ai-content-generator') . $file_path); } if (!class_exists('CURLFile')) { return new WP_Error('curlfile_missing', __('Server configuration error (CURLFile missing for file upload).', 'gpt3-ai-content-generator'), ['status' => 500]); } $url_builder_params = [ 'base_url' => $strategyInstance->get_base_url(), 'api_version' => $strategyInstance->get_api_version() ]; $url = OpenAIUrlBuilder::build('files', $url_builder_params); if (is_wp_error($url)) return $url; $mime_type = get_mime_type_from_filename_logic($strategyInstance, $original_filename); if (is_wp_error($mime_type)) { $mime_type = 'application/octet-stream'; } $cfile = new CURLFile($file_path, $mime_type, $original_filename); $data = ['purpose' => $purpose, 'file' => $cfile]; return _request_logic($strategyInstance, 'POST', $url, $data, true); } 